parameters.functionCode:
let info;
try { info = JSON.parse(($input.item.json.stdout || '{}').trim()); } catch { info = {}; }
const url = ($env.EMPIRE_CONSOLE_BASE_URL || 'http://localhost:4327') + '/check/money';
if (info.present === false) {
  return [{ json: {
    priority: 'P1',
    source: 'cache-staleness-watch',
    message: 'ops/cache/sync-log.json missing — nightly-refresh has never written a cache cycle.',
    url
  } }];
}
const age = parseFloat(info.ageHours);
if (!isFinite(age)) return [];
if (age >= 50) {
  return [{ json: {
    priority: 'P0',
    source: 'cache-staleness-watch',
    message: `Cache is ${age.toFixed(1)}h stale (≥50h). nightly-refresh has skipped at least 2 cycles. Dashboard money/traffic/SEO/contacts is showing old data.`,
    url
  } }];
}
if (age >= 26) {
  return [{ json: {
    priority: 'P1',
    source: 'cache-staleness-watch',
    message: `Cache is ${age.toFixed(1)}h stale (≥26h). nightly-refresh probably missed a cycle.`,
    url
  } }];
}
return [];
